START TRANSACTION;
DELETE FROM erp_job_title WHERE job_title_code IN ('JT-GM','JT-FIN-MGR','JT-HR-MGR','JT-IT-SPV','JT-PRC-STF','JT-CUS-STF','JT-PRD-MGR','JT-PPIC-SPV','JT-MIX-OPR','JT-COAT-OPR','JT-LAM-OPR','JT-PACK-OPR','JT-WH-MGR','JT-WH-STF','JT-LOG-STF','JT-QA-SPV','JT-QA-INS','JT-MNT-TECH','JT-RND-STF','JT-SLS-MGR','JT-SLS-STF');


UPDATE erp_job_title c JOIN erp_job_title p ON p.job_title_code='JT-GM' SET c.reports_to_job_title_id=p.id WHERE c.job_title_code IN ('JT-FIN-MGR','JT-HR-MGR','JT-PRD-MGR','JT-WH-MGR','JT-SLS-MGR');
UPDATE erp_job_title c JOIN erp_job_title p ON p.job_title_code='JT-PRD-MGR' SET c.reports_to_job_title_id=p.id WHERE c.job_title_code IN ('JT-PPIC-SPV','JT-QA-SPV','JT-MIX-OPR','JT-COAT-OPR','JT-LAM-OPR','JT-PACK-OPR','JT-MNT-TECH','JT-RND-STF');
UPDATE erp_job_title c JOIN erp_job_title p ON p.job_title_code='JT-WH-MGR' SET c.reports_to_job_title_id=p.id WHERE c.job_title_code IN ('JT-WH-STF','JT-LOG-STF');
UPDATE erp_job_title c JOIN erp_job_title p ON p.job_title_code='JT-FIN-MGR' SET c.reports_to_job_title_id=p.id WHERE c.job_title_code IN ('JT-PRC-STF','JT-CUS-STF');
UPDATE erp_job_title c JOIN erp_job_title p ON p.job_title_code='JT-QA-SPV' SET c.reports_to_job_title_id=p.id WHERE c.job_title_code='JT-QA-INS';
UPDATE erp_job_title c JOIN erp_job_title p ON p.job_title_code='JT-HR-MGR' SET c.reports_to_job_title_id=p.id WHERE c.job_title_code='JT-IT-SPV';
UPDATE erp_job_title c JOIN erp_job_title p ON p.job_title_code='JT-SLS-MGR' SET c.reports_to_job_title_id=p.id WHERE c.job_title_code='JT-SLS-STF';
COMMIT;
